// CreateIcpmsAiReviewJob is the resolver for the createIcpmsAiReviewJob field.
func (r *mutationResolver) CreateIcpmsAiReviewJob(ctx context.Context, input types.CreateIcpmsAiReviewJobInput) (*types.CreateIcpmsAiReviewJobPayload, error) {
	scope, err := r.authorize(ctx, input.OrganizationID, probo.ActionOrganizationUpdate)
	if err != nil {
		return nil, err
	}

	identity := authn.IdentityFromContext(ctx)

	airDoc, airDocErr := r.probo.IcpmsDocuments.Get(ctx, scope, input.DocumentID)
	fallbackAirCode := fmt.Sprintf("AIR-%s-%d", input.DocumentVersionID.String()[16:], time.Now().Unix())
	airCode := fallbackAirCode
	if airDocErr == nil {
		airCode = r.probo.IcpmsCodes.BusinessCodeForDocument(ctx, scope, input.OrganizationID, "AIR", airDoc, fallbackAirCode)
	}

	job := &coredata.IcpmsAiReviewJob{
		TenantID:          scope.GetTenantID(),
		OrganizationID:    input.OrganizationID,
		DocumentID:        input.DocumentID,
		DocumentVersionID: input.DocumentVersionID,
		JobCode:           airCode,
		ReviewScope:       coredata.IcpmsAiReviewScope(input.ReviewScope),
		AiProvider:        coredata.IcpmsAiProvider(input.AiProvider),
		AiModel:           input.AiModel,
		Status:            coredata.IcpmsAiReviewJobStatusQueued,
		CreatedBy:         identity.ID,
	}

	if err := r.probo.IcpmsAiReviews.Create(ctx, scope, job); err != nil {
		return nil, err
	}

	// Load Gemini API key now (before goroutine) so we don't need to pass the DB scope.
	var geminiAPIKey string
	var geminiModel string
	if input.AiProvider == types.IcpmsAiProviderGemini {
		if cfg, err := r.probo.IcpmsAiConfigs.Get(ctx, scope, input.OrganizationID, "GEMINI"); err == nil && cfg != nil && cfg.APIKey != nil {
			geminiAPIKey = *cfg.APIKey
		}
		if input.AiModel != nil && *input.AiModel != "" {
			geminiModel = *input.AiModel
		}
	}

	go func(bgJob *coredata.IcpmsAiReviewJob, bgScope coredata.Scoper) {
		bgCtx := context.Background()
		fallback := &probo.RuleBasedAIReviewProvider{}
		var provider probo.AIReviewProvider = fallback
		if bgJob.AiProvider == coredata.IcpmsAiProviderGemini && geminiAPIKey != "" {
			provider = &probo.GeminiAIReviewProvider{
				APIKey:   geminiAPIKey,
				Model:    geminiModel,
				Fallback: fallback,
			}
		}
		if err := r.probo.IcpmsAiReviews.RunJob(bgCtx, bgScope, bgJob, provider); err != nil {
			r.logger.ErrorCtx(bgCtx, "ai review job failed",
				log.String("job_id", bgJob.ID.String()),
				log.Error(err),
			)
		}
	}(job, scope)

	return &types.CreateIcpmsAiReviewJobPayload{Job: job}, nil
}

